#!/bin/sh
# Compile tools/vk_shaders/*.comp -> SPIR-V -> src/exr_vk_shaders.spv.inc
# Requires glslangValidator only at generation time (output is checked in).
set -e
ROOT=$(cd "$(dirname "$0")/.." && pwd)
GV="${GLSLANG:-glslangValidator}"
SD="$ROOT/tools/vk_shaders"
OUT="$ROOT/src/exr_vk_shaders.spv.inc"
TMP=$(mktemp -d)
SHADERS="resize_h resize_v premult color_matrix tonemap transfer lut3d convert \
gather_f32 scatter_f32 pred_partials pred_offsets pred_apply deinterleave \
interleave_encode predictor_encode channel_split channel_gather"
{
  echo "/* Generated by tools/gen_vk_shaders.sh - do not edit. SPIR-V compute"
  echo " * modules for the Vulkan backend, embedded as uint32 arrays. */"
} > "$OUT"
for s in $SHADERS; do
  "$GV" -V --target-env vulkan1.0 "$SD/$s.comp" -o "$TMP/$s.spv" >/dev/null
  printf 'static const uint32_t exr_vk_spv_%s[] = {\n' "$s" >> "$OUT"
  od -An -tx4 -v "$TMP/$s.spv" | awk '{for(i=1;i<=NF;i++) printf "0x%s,", $i} END{print ""}' >> "$OUT"
  printf '};\n' >> "$OUT"
done
rm -rf "$TMP"
echo "wrote $OUT"
